    /// `!` operators — no new dep, no new IR layer, no supertrait
    /// bound, no allocation, no [`Option`]-typed dispatch.
    fn is_interior_index(i: usize) -> bool {
        i < <Self as ClosedSet>::CARDINALITY && !<Self as ClosedSet>::is_endpoint_index(i)
    }

