    fn present_variants(items: &[Self]) -> ::std::vec::Vec<Self> {
        <Self as ClosedSet>::ALL
            .iter()
            .copied()
            .filter(|v| {
                items
                    .iter()
                    .any(|w| <Self as ClosedSet>::index_of(*v) == <Self as ClosedSet>::index_of(*w))
            })
            .collect()
    }

