    fn clamp(self, lo: Self, hi: Self) -> Self {
        if <Self as ClosedSet>::precedes(self, lo) {
            lo
        } else if <Self as ClosedSet>::precedes(hi, self) {
            hi
        } else {
            self
        }
    }

